COMPLEX16 calculate_h32FourierMode_zeroe(REAL8 eta, DynParamsCache *dc)
{
    REAL8 eta2 = eta*eta;
    REAL8 eta3 = eta2*eta;
    REAL8 v = dc->vPow[1], v2 = dc->vPow[2];

#define CPREF 0.8451542547285165775096183273659452926307858901134771889828170956
    REAL8 PN2 = CPREF*2.*(1.-3.*eta)/3.;
    REAL8 PN4 = CPREF*(-386. + 1450.*eta - 730.*eta2)/270.;
    REAL8 ImPN5 = CPREF*(14.*eta)/5.;
    REAL8 PN6 = CPREF*(-2902. - 34774.*eta + 200052.*eta2 - 32046.*eta3)/11880.;

    REAL8 lnxOx0p = log(v2/CONST_X0P);
    COMPLEX16 PN5_tail = CPREF*(-3.*I + 6.*I*lnxOx0p + 2.*CST_PI)*(1.-3.*eta)/3.;
    return v2*(PN2 + 
                v2*(PN4 + 
                    v*(I*ImPN5 + PN5_tail + 
                        v*PN6)));
#undef CPREF
}

