#define SQ1O42 0.1543033499620919102610944627639999204215524835
COMPLEX16 calculate_h30FourierModep(INT p, REAL8 eta, DynParamsCache *dc, PNEllipticEvaluator *pe)
{
    COMPLEX16 ret;
    INT pm = p;
    if (pm==0) return 0.0;
    INT pm2 = pm*pm;
    INT pm3 = pm2*pm;
    INT pm4 = pm2*pm2;
    INT pm5 = pm4*pm;
    REAL8 *ePow = dc->ePow;
    REAL8 *sq1m2Pow = dc->sq1mesqPow;
    REAL8 m1p3eta = -1. + 3.*eta;
    REAL8 y = sq1m2Pow[1];
    REAL8 yp = y+1.0, myp = -y+1.0;
    REAL8 yp2 = yp*yp, myp2 = myp*myp;
    REAL8 yp3 = yp2*yp, myp3 = myp2*myp;
    REAL8 yp4 = yp3*yp, myp4 = myp3*myp;
    REAL8 eta2 = eta*eta;
    REAL8 eta3 = eta2*eta;
#define EVALEJ(pp, qq, aa, bb) evaluate_Jpqab((pp), (qq), (aa), (bb), pe)
// #define EVALEJ(p, q, a, b) 1.0
#define SQ1M2(n) sq1m2Pow[n]
#define EPOW(n) ePow[n]
    REAL8 PN2, PN4, ImPN5, PN6;
    PN2 = SQ1O42*pm*m1p3eta*y*EVALEJ(pm,pm,0,0);

    PN4 = -0.05555555555555555*((79 + 2*(-121 + eta)*eta)*EVALEJ(pm,pm,1,0)*SQ1M2(2)) + 
        EVALEJ(pm,pm,0,0)*((-5 + eta)*m1p3eta - 
        ((19 + eta*(-63 + 11*eta))*SQ1M2(2))/6.) + 
        ((79 + 2*(-121 + eta)*eta)*EVALEJ(pm,pm,2,0)*SQ1M2(4))/18.;    
    PN4 *= SQ1O42*pm/(y);

    ImPN5 = (-9*EVALEJ(pm,pm,2,0))/5. + (3*EVALEJ(pm,pm,3,0))/2. - 
        (9*EVALEJ(pm,pm,4,0)*SQ1M2(2))/2.;   
    ImPN5 *= SQ1O42*eta*y;

    PN6 = -0.05555555555555555*(EVALEJ(pm,pm,1,0)*SQ1M2(2)*
        (-481 + 1431*eta + 122*eta2 + 2*eta3 + 
        (180 - 586*eta + 23*eta2 + 28*eta3)*SQ1M2(2))) - 
        (3*(5 - 17*eta + 6*eta2)*pm*EVALEJ(pm,pm,0,1)*SQ1M2(3))/2. + 
        EVALEJ(pm,pm,0,0)*((23 - 81*eta + 37*eta2 - 3*eta3)/2. + 
        (3*(5 - 17*eta + 6*eta2)*SQ1M2(1))/2. + 
        ((17 - 73*eta + 41*eta2 + 5*eta3)*SQ1M2(2))/3. - 
        ((5 - 17*eta + 6*eta2)*SQ1M2(3))/2. + 
        ((-4509 + 18099*eta - 10018*eta2 + 15*eta3)*SQ1M2(4))/792.) + 
        ((11395 - 30727*eta - 19264*eta2 + 4880*eta3)*EVALEJ(pm,pm,3,0)*SQ1M2(6))/
        792. + (EVALEJ(pm,pm,2,0)*(44*(-443 + 1404*eta - 182*eta2 + eta3)*SQ1M2(4) + 
        (4057 - 14825*eta + 7210*eta2 - 360*eta3)*SQ1M2(6)))/396. - 
        ((-97 + 1933*eta - 6704*eta2 + 976*eta3)*EVALEJ(pm,pm,4,0)*SQ1M2(8))/264.;
    PN6 *= SQ1O42 * pm / (sq1m2Pow[3]);

    REAL8 v = dc->vPow[1], v2 = dc->vPow[2];

    // tail part
    COMPLEX16 PN5_tail;
    COMPLEX16 lnIpvO2 =  pm>0 ? (log(0.5*pm) + 0.5*I*CST_PI) : (log(-0.5*pm) - 0.5*I*CST_PI);
    REAL8 lnxOx0p = log(v2/CONST_X0P);
    COMPLEX16 pref_tail;
    pref_tail = -3. + 6.*lnxOx0p + 4.*lnIpvO2;
    PN5_tail = -0.5*EVALEJ(pm,pm,2,0) + (5*EVALEJ(pm,pm,3,0))/4. - 
        (3*EVALEJ(pm,pm,4,0)*SQ1M2(2))/4.;
    PN5_tail *= I * SQ1O42 * m1p3eta * pref_tail * y;

    // print_debug("PN2 = %.16e\n", v2*PN2);
    // print_debug("PN4 = %.16e\n", dc->vPow[4]*PN4);
    // print_debug("ImPN5 = %.16e\n", dc->vPow[5]*ImPN5);
    // print_debug("PN6 = %.16e\n", dc->vPow[6]*PN6);
    // print_debug("PN5_tail = %.16e, %.16e\n", dc->vPow[5]*creal(PN5_tail), dc->vPow[5]*cimag(PN5_tail) );
    // return v2*PN0;
    return  v2*(PN2 + 
                v2*(PN4 + 
                    v*(I*ImPN5 + PN5_tail +
                        v*PN6)));
#undef EVALEJ
#undef SQ1M2
#undef EPOW
}

